#pragma once
#include <memory>
#include <primbench.hpp>

namespace Adapters {
  template <class WorkloadT>
  class PrimbenchRegistrar {
  public:
    // Called from the file-scope main() generated by the macro
    static int run(int argc, char *argv[]) {
      primbench::executor exec(argc, argv);

      auto stream = std::make_shared<hipStream_t>(hipStreamDefault);

      WorkloadT workload;
      workload.setup(stream);

      exec.run(WorkloadT{}.name(), [&]() {
        workload.reset_workload(stream);
        workload.run_workload(stream);
      });

      workload.teardown(stream);
      return 0;
    }
  };
} // namespace Adapters